package com.example.search.service;

import com.example.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.UUID;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public String index(Product product) throws Exception {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        Instant now = Instant.now();
        if (product.getCreatedAt() == null) product.setCreatedAt(now);
        product.setUpdatedAt(now);

        byte[] json = objectMapper.writeValueAsBytes(product);

        IndexRequest req = new IndexRequest(productsIndex)
                .id(product.getId())
                .source(json, XContentType.JSON)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);

        IndexResponse resp = client.index(req, RequestOptions.DEFAULT);
        return resp.getId();
    }

    public void upsert(Product product) throws Exception {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        Instant now = Instant.now();
        if (product.getCreatedAt() == null) product.setCreatedAt(now);
        product.setUpdatedAt(now);

        byte[] json = objectMapper.writeValueAsBytes(product);

        UpdateRequest req = new UpdateRequest(productsIndex, product.getId())
                .doc(json, XContentType.JSON)
                .docAsUpsert(true)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);

        client.update(req, RequestOptions.DEFAULT);
    }

    public void delete(String id) throws Exception {
        DeleteRequest req = new DeleteRequest(productsIndex, id)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        client.delete(req, RequestOptions.DEFAULT);
    }
}

package com.example.search.service;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final SearchQueryLogService queryLogService;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper, SearchQueryLogService queryLogService) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.queryLogService = queryLogService;
    }

    public SearchResponseDto search(SearchRequestDto req, String userId, String sessionId) throws Exception {
        SearchRequest searchRequest = new SearchRequest(productsIndex);

        SearchSourceBuilder source = new SearchSourceBuilder();
        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 10 : Math.min(100, Math.max(1, req.getSize()));
        source.from(page * size);
        source.size(size);

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        String q = req.getQuery();
        if (q == null || q.isBlank()) {
            bool.must(QueryBuilders.matchAllQuery());
        } else {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q, "name^4", "description^1", "brand^2", "category^2", "tags^2")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness(Fuzziness.AUTO)
                    .prefixLength(1);
            bool.must(mm);
        }

        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }
        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("category", req.getCategories()));
        }
        if (req.getAvailable() != null) {
            bool.filter(QueryBuilders.termQuery("available", req.getAvailable()));
        }
        if (req.getMinPrice() != null || req.getMaxPrice() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (req.getMinPrice() != null) range.gte(req.getMinPrice());
            if (req.getMaxPrice() != null) range.lte(req.getMaxPrice());
            bool.filter(range);
        }

        source.query(bool);

        String sort = req.getSort();
        if (sort == null || sort.isBlank() || "relevance".equalsIgnoreCase(sort)) {
        } else if ("price_asc".equalsIgnoreCase(sort)) {
            source.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC));
        } else if ("price_desc".equalsIgnoreCase(sort)) {
            source.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC));
        } else if ("rating_desc".equalsIgnoreCase(sort)) {
            source.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC));
        } else if ("newest".equalsIgnoreCase(sort)) {
            source.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC));
        }

        source.aggregation(AggregationBuilders.terms("facet_brand").field("brand").size(20));
        source.aggregation(AggregationBuilders.terms("facet_category").field("category").size(50));
        source.aggregation(AggregationBuilders.terms("facet_tags").field("tags").size(50));
        source.aggregation(AggregationBuilders.terms("facet_available").field("available").size(2));

        searchRequest.source(source);

        SearchResponse resp = client.search(searchRequest, RequestOptions.DEFAULT);

        long total = resp.getHits().getTotalHits() == null ? 0 : resp.getHits().getTotalHits().value;

        List<Product> items = new ArrayList<>();
        for (SearchHit hit : resp.getHits().getHits()) {
            Product p = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            items.add(p);
        }

        Map<String, List<SearchResponseDto.FacetBucket>> facets = new LinkedHashMap<>();
        facets.put("brand", termsToBuckets((Terms) resp.getAggregations().get("facet_brand")));
        facets.put("category", termsToBuckets((Terms) resp.getAggregations().get("facet_category")));
        facets.put("tags", termsToBuckets((Terms) resp.getAggregations().get("facet_tags")));
        facets.put("available", termsToBuckets((Terms) resp.getAggregations().get("facet_available")));

        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setQuery(req.getQuery());
        log.setFilters(req.toFilterMap());
        log.setResultCount((int) Math.min(Integer.MAX_VALUE, total));
        log.setUserId(userId);
        log.setSessionId(sessionId);
        log.setTimestamp(Instant.now());
        queryLogService.log(log);

        return new SearchResponseDto(total, items, facets);
    }

    private List<SearchResponseDto.FacetBucket> termsToBuckets(Terms terms) {
        if (terms == null) return List.of();
        return terms.getBuckets().stream()
                .map(b -> new SearchResponseDto.FacetBucket(String.valueOf(b.getKey()), b.getDocCount()))
                .collect(Collectors.toList());
    }
}

package com.example.search.service;

import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

@Service
public class SearchQueryLogService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Value("${elasticsearch.index.queries:search_queries}")
    private String queriesIndex;

    public SearchQueryLogService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public void log(SearchQueryLog log) throws Exception {
        byte[] json = objectMapper.writeValueAsBytes(log);
        IndexRequest req = new IndexRequest(queriesIndex)
                .id(log.getId())
                .source(json, XContentType.JSON)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.NONE);
        client.index(req, RequestOptions.DEFAULT);
    }
}

package com.example.search.web;

import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexService indexService;

    public ProductController(ProductIndexService indexService) {
        this.indexService = indexService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public Product create(@RequestBody Product product) throws Exception {
        String id = indexService.index(product);
        product.setId(id);
        return product;
    }

    @PutMapping("/{id}")
    public void upsert(@PathVariable String id, @RequestBody Product product) throws Exception {
        product.setId(id);
        indexService.upsert(product);
    }

    @DeleteMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void delete(@PathVariable String id) throws Exception {
        indexService.delete(id);
    }
}

